// Parse source pack and build Claude prompt
const sourcePack = JSON.parse($input.first().json.data);
const peptideName = sourcePack.peptide.name;
const aliases = sourcePack.peptide.aliases || [];
const category = sourcePack.peptide.category;
const sources = sourcePack.sources || [];
const trials = sourcePack.trials || [];

// Build citations reference section
let citationsRef = 'Available Citations:\n';
for (const source of sources) {
  citationsRef += `- ${source.id}: "${source.title}" (${source.year}, ${source.studyType}, ${source.subjects})\n`;
}

// Build trials reference section
let trialsRef = '\nClinical Trials:\n';
for (const trial of trials) {
  trialsRef += `- ${trial.nctId}: "${trial.title}" (${trial.status}, Phase ${trial.phase})\n`;
}

// The dossier template prompt
const systemPrompt = `You are a medical research writer creating evidence-based peptide dossiers for Peptide Library. 

RULES:
1. NEVER include dosing information, injection instructions, or sourcing/purchasing guidance
2. ALWAYS cite sources using [sourceId] format (e.g., [PMID:12345678])
3. Label preclinical/animal studies with "(animal study)" or "(in-vitro)"
4. Use hedged language: "may," "research suggests," "studies indicate"
5. Include EvidenceBadge components with appropriate level (high/moderate/low/preclinical)
6. Output valid MDX format with proper frontmatter

CATEGORY DEFINITIONS:
- metabolic: GLP-1 agonists, weight management, insulin sensitizers
- repair-recovery: BPC-157, TB-500, tissue healing peptides
- hormonal: Growth hormone secretagogues, hormone modulators
- cognitive: Nootropics, neuroprotective peptides
- other: Antimicrobial, cosmetic, other applications`;

const userPrompt = `Create a comprehensive research dossier for ${peptideName} (${category} category).

Aliases: ${aliases.join(', ') || 'None'}

${citationsRef}
${trialsRef}

Generate MDX with these 12 sections:

1. **Frontmatter** (YAML):
\`\`\`yaml
---
layout: ../../layouts/DossierLayout.astro
title: "${peptideName} Research Summary"
peptide: "${peptideName}"
category: "${category}"
aliases: [${aliases.map(a => `"${a}"`).join(', ')}]
lastUpdated: "${new Date().toISOString().split('T')[0]}"
evidenceLevel: "[high|moderate|low|preclinical]"
studyCount: ${sources.length}
humanTrials: ${trials.filter(t => t.status === 'completed').length}
---
\`\`\`

2. **Quick Facts** - Summary box with key stats
3. **What Is [Peptide]?** - Plain-language explanation of mechanism
4. **Mechanism of Action** - Scientific explanation with receptor/pathway details
5. **Research Applications** - Current research areas with evidence levels
6. **Clinical Evidence** - Human trial summaries with citations
7. **Preclinical Research** - Animal/in-vitro studies with clear labeling
8. **Safety Profile** - Known side effects, contraindications from literature
9. **Ongoing Research** - Active clinical trials from the trials list
10. **Related Peptides** - Similar compounds in the same category
11. **Citation Table** - Full reference list using CitationTable component
12. **Medical Disclaimer** - Standard disclaimer about educational content

IMPORTANT:
- Use <EvidenceBadge level="high|moderate|low|preclinical" /> component for evidence ratings
- Use <CitationTable sources={[]} /> for the references section
- Every claim must have a [citation] in brackets
- Clearly distinguish human vs animal research
- NO dosing, NO sourcing, NO medical advice`;

return {
  json: {
    systemPrompt: systemPrompt,
    userPrompt: userPrompt,
    peptideName: peptideName,
    outputFileName: `${peptideName.toLowerCase().replace(/\s+/g, '-')}.mdx`,
    sourcePack: sourcePack
  }
};

// Parse Claude response and extract MDX content
const response = $input.first().json;
const previousData = $('Build Claude Prompt').first().json;

// Extract content from Claude response
let mdxContent = '';
if (response.content && response.content[0] && response.content[0].text) {
  mdxContent = response.content[0].text;
}

// Clean up the MDX content
// Remove any markdown code blocks wrapping the entire content
if (mdxContent.startsWith('```mdx')) {
  mdxContent = mdxContent.replace(/^```mdx\n/, '').replace(/\n```$/, '');
} else if (mdxContent.startsWith('```')) {
  mdxContent = mdxContent.replace(/^```\n/, '').replace(/\n```$/, '');
}

// Ensure frontmatter is properly formatted
if (!mdxContent.startsWith('---')) {
  // Try to find frontmatter in the content
  const frontmatterMatch = mdxContent.match(/---[\s\S]*?---/);
  if (frontmatterMatch) {
    mdxContent = mdxContent.substring(mdxContent.indexOf('---'));
  }
}

return {
  json: {
    mdxContent: mdxContent,
    peptideName: previousData.peptideName,
    outputFileName: previousData.outputFileName,
    tokensUsed: response.usage?.output_tokens || 0,
    model: response.model || 'claude-sonnet-4-20250514'
  }
};
